import Card from "@mui/material/Card";
import CardActions from "@mui/material/CardActions";
import CardContent from "@mui/material/CardContent";
import CardMedia from "@mui/material/CardMedia";
import Typography from "@mui/material/Typography";
import Button from "@mui/material/Button";
import React from "react";
import { makeStyles } from "@material-ui/core/styles";
import project1 from "./assets/21.jpg";
const useStyles = makeStyles((theme) => ({
  experience: {
    color: 'white',
    width: '500px',
    height: '200px'
  },
  expdes:{
    display:'block'
  }
}));
const Projects = () => {
  const projects = [];
  const classes = useStyles();
  return (
    <React.Fragment>
      <div style={{ height:'100vh', marginTop: '70px', backgroundColor:'black',  }}>
        <div>
          <span style={{fontSize: '30px', color:'white'}}> Experience</span>
          <div style={{display: 'flex',flexDirection: 'row',}}>
          <div className={classes.experience}>Web Developer
          </div>
          <div className={classes.experience}>Software Engineer <span className="expdes"></span><span className={classes.expdes}> <ul><li>Responsibilities</li></ul></span></div>
        </div>
        </div>
        <div>
          <span style={{fontSize: '30px', color:'white'}} >Projects</span>
          <Card style={{ width: "350px" }}>
            <CardMedia
              component="img"
              alt="soil monitoring"
              height="140"
              image={project1}
            />
            <CardContent>
              <Typography gutterBottom variant="h5" component="div">
                Soil Monitoring
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Project Description
              </Typography>
            </CardContent>
            <CardActions>
              <Button size="small">More Information...</Button>
            </CardActions>
          </Card>
        </div>
      </div>
    </React.Fragment>
  );
};
export default Projects;
